export const UFRJ_2024_QUESTIONS: any[] = [
  { id: 'ufrj_2024_001', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 50 anos, queixa-se de perda ponderal progressiva, dor abdominal em andar superior do abdome e prurido. Com icterícia, colúria e acolia. Recebeu diagnóstico de adenocarcinoma de região periampular, o qual posteriormente foi afastado, confirmando-se doença relacionada à imunoglobulina (Ig) G4. Pode- se afirmar que, mais provavelmente, o que resultou nesse novo diagnóstico foi a presença de:', options: ['pâncreas em salsicha em exame de imagem abdominal', 'nódulo de Irmã Maria José no exame físico', 'tromboflebite superficial migratória', 'quadro de depressão com ideação suicida'], correctIndex: 0 },
  { id: 'ufrj_2024_002', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 49 anos, com diagnóstico recente de adenoma de paratireoide, é admitida no setor de emergência com quadro de letargia. Eletrocardiograma (ECG): bradicardia sinusial. Exames laboratoriais: cálcio sérico (Ca++) = 13mg/dL; sódio sérico (Na+) = 142mEq/L; potássio sérico (K+) = 4,5mEq/L. Pode-se afirmar que, inicialmente, o tratamento mais adequado é:', options: ['bifosfonado intravenoso', 'diurético de alça intravenoso', 'solução salina intravenosa', 'hidrocortisona intravenosa'], correctIndex: 2 },
  { id: 'ufrj_2024_003', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar, na avaliação de vertigem aguda, que o mais sugestivo de etiologia labiríntica é:', options: ['ausência do sinal de Romberg', 'nistagmo para baixo (downbeating)', 'presença de desalinhamento vertical dos olhos (skew deviation)', 'teste do impulso da cabeça anormal (head impulse test)'], correctIndex: 3 },
  { id: 'ufrj_2024_004', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 85 anos, relata perda de peso não intencional nos últimos meses. Diagnóstico: sarcopenia do envelhecimento. Pode-se afirmar que, com objetivo de aumentar a sobrevida livre de dependência funcional, a melhor conduta é recomendar:', options: ['hormônio do crescimento', 'testosterona', 'exercício físico', 'vitamina D'], correctIndex: 2 },
  { id: 'ufrj_2024_005', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'A Miastenia Gravis é uma doença da junção neuromuscular que se caracteriza for fraqueza e fatigabilidade dos músculos esqueléticos. Pode-se afirmar que ela decorre por:', options: ['diminuição de acetilcolina na membrana pós-sináptica', 'diminuição de acetilcolina na membrana pré-sináptica', 'aumento de acetilcolina na membrana pós- sináptica', 'aumento de acetilcolina na membrana pré- sináptica'], correctIndex: 0 },
  { id: 'ufrj_2024_006', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'O envelhecimento humano é marcado por diversos processos moleculares, incluindo a perda da proteostase. Pode-se afirmar que um dos indícios de tal processo, detectado ao exame microscópico, é o acúmulo de:', options: ['pigmento antracótico em macrófagos alveolares', 'glicogênio em células escamosas do esôfago', 'lipofuscina em hepatócitos', 'melanina em queratinócitos basais da epiderme'], correctIndex: 2 },
  { id: 'ufrj_2024_007', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 69 anos, comparece ao setor de emergência ortopédica queixando de claudicação e dor no quadril direito. Radiografia: lesão lítica insuflante na metáfise proximal do fêmur com aspecto de agressividade. Investigação diagnóstica subsequente: predomínio de plasmócitos neoplásicos no exame histopatológico da lesão lítica; ausência de tumor primário na tomografia computadorizada (TC) do tórax e abdome; ausência de proteína M no plasma e na urina; exames laboratoriais sem alterações. Biópsia da medula óssea: sem evidência de plasmócitos neoplásicos. A principal hipótese diagnóstica é:', options: ['plasmocitoma', 'gamopatia monoclonal de significado indeterminado', 'mieloma múltilplo', 'mieloma assintomático'], correctIndex: 0 },
  { id: 'ufrj_2024_008', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que, nos pacientes em uso crônico de inibidor da angiotensina, o antimicrobiano que deve ser evitado, pelo risco de cardiotoxicidade é:', options: ['amicacina', 'vancomicina', 'sulfametoxazol-trimetoprim', 'ceftriaxona'], correctIndex: 2 },
  { id: 'ufrj_2024_009', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Atualmente, os surtos de doença de Chagas estão relacionados à via de infecção oral. Pode-se afirmar, com relação às manifestações clínicas e prognóstico, que essa forma de transmissão se difere da forma vetorial por:', options: ['˂ chance de encefalite', '˃ período de incubação', '˃ risco de miocardite', '˂ mortalidade'], correctIndex: 2 },
  { id: 'ufrj_2024_010', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar, ao se comparar os anticoagulantes orais diretos, que o de menor excreção renal é a:', options: ['dabigatrana', 'rivaroxabana', 'edoxabana', 'apixabana'], correctIndex: 3 },
  { id: 'ufrj_2024_011', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 45 anos, com esclerose sistêmica difusa iniciada há 2 anos, é admitida no setor de emergência com oligúrica, pressão arterial sistêmica (PA) = 220 x 130mmHg e creatinina (Cr) = 4,5mg/dL. Pode-se afirmar que o fármaco melhor indicado para o tratamento dessa complicação é:', options: ['captopril', 'furosemida', 'espironolactona', 'atenolol'], correctIndex: 0 },
  { id: 'ufrj_2024_012', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 60 anos, apresenta cefaleia e perda visual. TC: massa supra selar sólida e parcialmente calcificada. A principal hipótese é de um tumor benigno que se origina de remanescentes da bolsa de Rathke. Pode-se afirmar que o tumor em questão é o:', options: ['ependimoma', 'astrocitoma', 'meningioma', 'craniofaringioma'], correctIndex: 3 },
  { id: 'ufrj_2024_013', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 30 anos, tem quadro de hipertensão arterial sistêmica (HAS) de diagnóstico recente e difícil controle. Refere episódios de palpitação, cefaleia e sudorese profusa; nega diarreia. TC do abdome: massa em suprarrenal direita. Pode-se afirmar que o exame melhor indicado para confirmar o suposto diagnóstico é a dosagem de:', options: ['concentração de aldosterona plasmática', 'ácido vanilmandélico sérico', 'catecolaminas e metanefrinas séricas e urinárias', 'ácido 5-hidroxiindoleacético sérico'], correctIndex: 2 },
  { id: 'ufrj_2024_014', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que, no exame físico neurológico no qual o examinador pede para o paciente encolher os ombros e rodar a cabeça para os lados contra resistência, o nervo craniano testado é o:', options: ['troclear', 'glossofaríngeo', 'hipoglosso', 'acessório'], correctIndex: 3 },
  { id: 'ufrj_2024_015', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar, à cintilografia pulmonar de ventilação/perfusão (V/Q), que o resultado mais compatível com o diagnóstico de tromboembolismo pulmonar é:', options: ['defeito de ventilação sem correspondente perfusão anormal', 'defeito de perfusão sem correspondente ventilação anormal', 'ausência de perfusão e ventilação em uma área pulmonar', 'hiperperfusão e ventilação aumentada em uma área pulmonar'], correctIndex: 1 },
  { id: 'ufrj_2024_016', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 18 anos, queixa-se de lesões pruriginosas em cotovelos e joelhos, que surgiram há 2 anos. Exame físico: pápulas e vesículas sob base eritematosa em cotovelos, joelhos e nádegas. Exame histopatológico: infiltrado neutrofílico nas papilas dérmicas. Imunofluorescência direta de área perilesional: depósitos granulares de IgA nas papilas dérmicas. A principal hipótese diagnóstica é:', options: ['dermatite herpetiforme', 'dermatose por IgA linear', 'pênfigo vulgar', 'penfigoide bolhoso'], correctIndex: 0 },
  { id: 'ufrj_2024_017', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Nos Estados Unidos da América (EUA), em 2018, a maconha foi utilizada por 43 milhões de pessoas. De 2008 a 2017, a concentração de tetrahidrocanabinol (THC) aumentou de 8,9 para 17,1% e, atualmente, em alguns preparados para vaping chega até 95%. Analise as afirmativas a seguir sobre o uso de maconha: I) Craving pela substância, dificuldade para desempenhar o papel acadêmico ou profissional, ansiedade, inquietação, insônia e redução do apetite após a cessação do seu uso são sintomas que podem indicar um padrão problemático do uso de maconha. II) Idade precoce de início do uso da substância, frequência de uso e exposição a maconha com alta concentração de THC aumentam o risco do desenvolvimento de um transtorno mental e do comportamento por uso de cannabis. III) O uso de preparações comestíveis de maconha (edibles) não está relacionado ao risco de overdose. Pode-se afirmar que está(ão) correta(s) a(s) afirmativa(s):', options: ['II', 'I', 'I e II', 'II e III'], correctIndex: 2 },
  { id: 'ufrj_2024_018', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 35 anos, previamente hígido, refere quadro de febre sem padrão definido, fadiga e tosse seca há cerca de 1 semana. Os sintomas iniciaram após retorno de férias na região centro-oeste do Brasil, onde praticou ecoturismo. TC do tórax: nódulo periférico com discreto halo em vidro fosco e adenomegalia hilar correspondente. Pode-se afirmar, tendo em vista a principal hipótese diagnóstica que:', options: ['a presença de eritema nodoso e artrite representam, na maioria das vezes, manifestações inflamatórias reativas', 'mesmo em pacientes imunocompetentes, o tratamento está indicado a fim de evitar-se complicações futuras', 'mediastinite fibrosante é uma complicação rara, de comportamento benigno e com boa resposta ao tratamento convencional', 'não é comum a evolução com calcificação do linfonodo hilar ou do nódulo pulmonar'], correctIndex: 0 },
  { id: 'ufrj_2024_020', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 37 anos, afrodescendente, sem comorbidades, apresenta agudamente lesões cutâneas tipo eritema nodoso nos membros inferiores e dores articulares. Radiografia do tórax: adenopatia hilar bilateral. Evolui com lesões cutâneas na face sugestivas de lúpus pérnio. Pode-se afirmar que esse quadro agudo é mais sugestivo de:', options: ['síndrome de Löfgren associada a sarcoidose', 'doença de Poncet associada a tuberculose', 'síndrome de Mikulicz associada a síndrome de Sjögren', 'lúpus eritematoso sistêmico (LES)'], correctIndex: 0 },
  { id: 'ufrj_2024_021', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 60 anos, hipertenso controlado, com insuficiência cardíaca de fração reduzida (ICFER), apresenta cansaço aos pequenos esforços. Está em uso de sacubitril-valsartana, carvedilol e espironolactona. Pode-se afirmar que o fármaco a ser associado, com propriedade de reduzir a progressão da insuficiência cardíaca, ou risco de morte de causa cardiovascular, é:', options: ['hidralazina', 'anlodipina', 'dapaglifozina', 'furosemida'], correctIndex: 2 },
  { id: 'ufrj_2024_022', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Algumas doenças hereditárias monogênicas renais com variante genética patogênica já determinada podem ter seu fenótipo mimetizado por ação de fármacos que atuam diretamente nas mesmas proteínas. Pode-se afirmar que representa corretamente um fármaco, seus efeitos hidroeletrolíticos e uma doença hereditária com a mesma apresentação fenotípica, respectivamente:', options: ['hidroclorotiazída / hipopotassemia, alcalose metabólica, hipotensão arterial sistêmica / síndrome de Gitelman', 'furosemida / hipopotassemia, acidose metabólica, hipotensão arterial sistêmica / síndrome de Bartter', 'amiloride / hiperpotassemia, acidose metabólica, hipotensão arterial sistêmica / síndrome de Liddle', 'acetazolamida / hiperpotassemia, alcalose metabólica, hipertensão arterial sistêmica / acidose tubular renal proximal'], correctIndex: 0 },
  { id: 'ufrj_2024_023', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que a condição associada ao desdobramento paradoxal da segunda bulha cardíaca é:', options: ['estenose mitral', 'bloqueio do ramo esquerdo', 'insuficiência aórtica', 'embolia pulmonar'], correctIndex: 1 },
  { id: 'ufrj_2024_024', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Nos EUA, há uma verdadeira crise de abuso de opioides. Apesar de no Brasil o quadro não ser tão calamitoso, é preciso que todo médico esteja preparado para rapidamente reconhecer e tratar uma overdose destas substâncias. Pode-se afirmar, neste contexto, que:', options: ['à monitorização cardíaca, isquemia miocárdica e intervalo QT encurtado são eventualmente observados', 'respiração superficial e lenta, hipertermia, midríase e bradicardia estão tipicamente presentes', 'lacrimejamento, rinorreia, dores musculares, inquietação e diarreia são frequentes nos jovens', 'apesar de raro, quadros convulsivos às vezes ocorrem nos casos de uso de altas doses de tramadol'], correctIndex: 3 },
  { id: 'ufrj_2024_025', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 68 anos, que já apresentou um episódio de cólica biliar não complicada, tem indicação de colecistectomia eletiva por cálculos na vesícula. No momento, assintomático. Tem HAS controlada com losartana. Refere apendicectomia aos 25 anos, sem intercorrências. Na consulta para avaliação do risco cirúrgico, exame físico normal. Radiografia do tórax e ECG em repouso normais; hemograma, glicemia e bioquímica normais. Coagulograma: tempo de atividade da protrombina (TAP) = 11 segundos; índice internacional normalizado (INR) = 0,96; tempo de tromboplastina parcial ativada (PTTa) = 46 segundos (paciente) /31 segundos (controle); relação paciente/controle = 1,48. Pode-se afirmar que, neste momento, a melhor conduta é:', options: ['liberá-lo para realizar o procedimento cirúrgico com a orientação de prescrição intraoperatória de plasma fresco congelado', 'realizar pesquisa de anticoagulante lúpico e dos fatores da coagulação da via extrínseca', 'solicitar pesquisa de anticardiolipinas e dosagem de todos os fatores da coagulação', 'solicitar pesquisa de anticoagulante lúpico e dos fatores da coagulação da via intrínseca'], correctIndex: 3 },
  { id: 'ufrj_2024_026', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que a dificuldade do paciente, com dor lombar, para andar na ponta dos pés indica comprometimento da raiz nervosa:', options: ['S1', 'L2', 'L4', 'L5'], correctIndex: 0 },
  { id: 'ufrj_2024_027', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que a variável determinante da oferta de oxigênio tecidual (DO ) de menor importância é: 2', options: ['volume sanguíneo', 'pressão parcial arterial de oxigênio (PaO ) 2', 'níveis sanguíneos de hemoglobina (Hb)', 'contratilidade miocárdica'], correctIndex: 1 },
  { id: 'ufrj_2024_028', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que a correlação entre audição da vibração dentro do ciclo cardíaco c Diagrama representando os principais sopros Legenda: B1 = primeira bulha cardíaca, B2 = segun Tipo de sopro A – Sopro pré-sistólico de uma estenose mitra B – Sopro contínuo de um canal arterial patent C – Sopro diastólico aórtico D – Sopro pansistólico de uma regurgitação m E – Sopro de ejeção aórtica começando com u', options: ['figura 1 - letra A; figura 2 - letra D; figura 3 - let', 'figura 1 - letra C; figura 2 - letra D; figura 3 - let', 'figura 1 - letra C; figura 2 - letra D; figura 3 - let', 'figura 1 - letra A; figura 2 - letra D; figura 3 - let e os diagramas ilustrativos do momento da com o mais provável sopro cardíaco é: cardíacos: nda bolha cardíaca, Fig. = figura. al te mitral um clique de ejeção tra E; figura 4 - letra C; figura 5 -letra B tra E; figura 4 - letra A; figura 5 - letra B tra E; figura 4 - letra B; figura 5 - letra A tra B; figura 4 - letra C; figura 5 - letra E'], correctIndex: 0 },
  { id: 'ufrj_2024_029', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 68 anos, apresentou a alteração Analise as afirmativas: I) Os sinais clínicos de miose e ptose palp possibilidade de tumor de Pancoast. II) Uma TC do tórax não seria útil para avali relação com as estruturas adjacentes. III) Este tumor representa um tipo diferenciado Pode-se afirmar que está(ão) correta(s) a(s) afi', options: ['II e III', 'I', 'II', 'I e III o assinalada no escanograma de tórax: pebral, enoftalmia e anidrose aumentariam a iação da densidade da lesão apical e da sua o do estágio III da doença. irmativa(s):'], correctIndex: 3 },
  { id: 'ufrj_2024_030', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 19 anos, queixa-se de edema facial, aumento do volume abdominal e edema vespertino em membros inferiores. Elementos anormais e sedimentoscopia (EAS) a seguir: Pode-se afirmar que o resultado observado é compatível com:', options: ['lipiduria', 'infecção por Paracoccidioides brasiliensis', 'cristaluria', 'infecção por Histoplasma capsulatum'], correctIndex: 0 },
  { id: 'ufrj_2024_032', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar, sobre a hérnia inguinal na infância, que:', options: ['o tratamento é expectante até os dois anos de idade, principalmente no sexo feminino', 'é causada pela persistência do conduto peritônio-vaginal e seu tratamento cirúrgico é a ligadura alta do saco herniário', 'é uma doença adquirida e seu tratamento é a correção cirúrgica, com o uso de material prostético', 'na presença de encarceramento herniário, mesmo na vigência de peritonite, sempre tenta-se a redução manual'], correctIndex: 1 },
  { id: 'ufrj_2024_033', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 48 anos, sem comorbidades, é admitida no setor de emergência com edema de membro inferior esquerdo desde a raiz da coxa, de início súbito há 2 dias. Ecodoppler venoso de membros inferiores e veias ilíacas: trombose de veia ilíaca externa de aspecto recente. A conduta mais adequada para esta paciente é:', options: ['anticoagulação plena após trombectomia venosa', 'anticoagulação plena e implante de filtro de veia cava removivel', 'anticoagulação plena e implante de filtro de veia cava permanente', 'anticoagulação plena'], correctIndex: 3 },
  { id: 'ufrj_2024_034', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Analise as afirmativas a seguir sobre trauma pancreático: I) Após um trauma abdominal a presença de lesão pancreática isolada não é comum, ao contrário, ela, na maioria das vezes, é acompanhada de lesões de outros órgãos. II) O segmento mais comumente acometido é o corpo pancreático. III) Quando a dosagem de amilase sérica está normal, pode-se descartar a possibilidade de trauma pancreático. Pode-se afirmar que está(ão) correta(s) a(s) afirmativa(s):', options: ['II e III', 'I', 'II', 'I e II'], correctIndex: 3 },
  { id: 'ufrj_2024_035', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 39 anos, sem comorbidades, vítima de atropelamento, é admitido no setor de emergência estável hemodinamicamente, apresentando ferida corto-contusa, de 0,5cm, no terço médio da perna. Radiografia: fratura da diáfise da tíbia direita com traço transverso. Não há outras lesões associadas. Pode-se afirmar que o tipo de fratura, de acordo com a classificação de Gustilo para fratura exposta e o(s) antibiótico(s) indicado(s) é (são):', options: ['I / cefazolina', 'II / cefazolina + gentamicina', 'IIIA / cefazolina + gentamicina + penicilina', 'IIIB / cefazolina + gentamicina + penicilina'], correctIndex: 0 },
  { id: 'ufrj_2024_036', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 55 anos, apresenta linfoadenomegalia cervical direita, sem outros sintomas. Avaliação histopatológica da biópsia do linfonodo: carcinoma escamoso metastático para linfonodo. Investigação para sítio primário: tumor primário em amígdala palatina direita. Pode-se afirmar que o tipo de vírus associado ao carcinoma escamoso que deve ser pesquisado, pois está relacionado a um melhor prognóstico, é:', options: ['vírus Epstein-Barr', 'citomegalovírus', 'papiloma vírus humano', 'herpes simples vírus'], correctIndex: 2 },
  { id: 'ufrj_2024_037', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 31 anos, com histórico de constipação crônica, queixa-se de sangramento em papel após evacuação. Refere, também, dor anal ao evacuar. Nega melena ou hematoquezia, dor abdominal ou perda ponderal. Sem antecedentes familiares relevantes. Exame físico do abdome sem alterações. Exames laboratoriais: Hb = 14,7g/dL; leucócitos = 6.200/mm³; plaquetas = 350.000/mm³; ureia = 32mg/dL; creatinina = 0,9mg/dL; albumina = 4,2mg/dL. A hipótese diagnóstica mais provável é:', options: ['adenocarcinoma de cólon', 'fissura anal', 'angiectasia de cólon', 'diverticulite aguda'], correctIndex: 1 },
  { id: 'ufrj_2024_038', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Analise as afirmativas a seguir sobre a imunologia do transplante de órgãos e a rejeição de aloenxerto: I) A rejeição hiperaguda ocorre dentro de minutos a dias após o transplante. II) A rejeição aguda é um processo mediado mais comumente por células T e geralmente ocorre nas primeiras semanas a meses de transplante. III) O controle imunológico, com objetivo de limitar os episódios de rejeição aguda e o desenvolvimento de anticorpos específicos do doador, não altera a ocorrência de rejeição. Pode-se afirmar que está(ão) correta(s) a(s) afirmativa(s):', options: ['I e II', 'I', 'II', 'II e III'], correctIndex: 0 },
  { id: 'ufrj_2024_039', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'A colite isquêmica é uma condição que acomete mais frequentemente o cólon esquerdo, incluindo o ângulo esplênico do cólon. Pode-se afirmar que as duas áreas bem definidas, onde a circulação colateral do cólon é classicamente inconsistente e vulnerável a isquemia, são:', options: ['Griffiths point (flexura esplênica) e arcada de Riolan (junção retosigmoide)', 'Griffiths point (flexura esplênica) e Sudeck´s point (junção retossigmoide)', 'Sudeck´s point (junção retossigmoide) e arcada de Riolan (flexura hepática)', 'Sudeck´s point (flexura esplênica) e arcada de Riolan (flexura hepática)'], correctIndex: 1 },
  { id: 'ufrj_2024_040', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'O VIPoma é um tumor de células das ilhotas pancreáticas secretoras de peptídeo intestinal vasoativo (VIP), o que resulta em um quadro de diarreia aquosa, hipopotassemia e acloridria. Pode-se afirmar que esse quadro é conhecido por síndrome de:', options: ['Cushing', 'Zollinger-Ellison', 'Sipple', 'Werner-Morrison'], correctIndex: 3 },
  { id: 'ufrj_2024_041', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Analise as afirmativas a seguir sobre os componentes da estratégia perioperatória de reanimação hemostática ou de controle de danos no choque hemorrágico traumático: I) Minimiza-se o uso de cristaloides venosos e se adota hipotensão permissiva até o controle definitivo do sangramento. II) Inicialmente, é apropriado o uso venoso de solução salina hipertônica. III) Guia-se a transfusão de componentes sanguíneos pelos resultados dos exames laboratoriais. Pode-se afirmar que está(ão) correta(s) a(s) afirmativa(s):', options: ['II', 'I', 'I e II', 'II e III'], correctIndex: 2 },
  { id: 'ufrj_2024_042', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'No pós-operatório, paciente apresentou formação de um quelóide em ferida cirúrgica. Pode-se afirmar que uma das características dessa cicatrização anormal é:', options: ['que é incomum a ocorrência em membros superiores e face', 'a formação de cicatriz elevada que cresce dentro dos limites da ferida', 'que frequentemente há regressão espontânea com o passar do tempo', 'a presença de diferenças histológicas em comparação a cicatriz hipertrófica'], correctIndex: 3 },
  { id: 'ufrj_2024_043', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Analise as afirmativas: I) O transplante renal é contraindicado em usuários de drogas venosas. II) O transplante renal com doador vivo não pode ser realizado entre pessoas de diferentes grupos AB0. III) O lúpus eritematoso sistêmico tem alta taxa de recorrência no enxerto renal e é causa frequente de perda do mesmo. Pode-se afirmar que está(ão) correta(s) a(s) afirmativa(s):', options: ['I e III', 'II', 'I', 'II e III'], correctIndex: 2 },
  { id: 'ufrj_2024_044', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 45 anos, com neoplasia metastática em parênquima hepático, será submetido a tratamento cirúrgico. O cirurgião planeja uma hepatectomia esquerda estendida. Pode-se afirmar que, de acordo com a anatomia funcional hepática, haverá a ressecção dos segmentos:', options: ['I, II, III, IV e V', 'II, III, IV, V e VIII', 'I, II, III, IV, V e VIII', 'II, III, IV e V'], correctIndex: 1 },
  { id: 'ufrj_2024_045', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que a tromboflebite migratória ocorre mais frequentemente na neoplasia do:', options: ['estômago', 'pâncreas', 'esôfago', 'cólon'], correctIndex: 1 },
  { id: 'ufrj_2024_046', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 75 anos, com colelitíase, foi submetida a colecistectomia videolaparoscópica. No intraoperatório, observou-se dilatação de vias biliares, consequentemente se realizou uma colangiografia que evidenciou colédoco de 3cm contendo cálculo de cerca de 2cm em seu interior. A seguir, a conduta mais adequada é realizar colecistectomia e:', options: ['drenagem de via biliar utilizando dreno de Kehr', 'coledocotomia para retirada de cálculo', 'colangiopancreatografia endoscópica retrógrada, posteriormente', 'confecção de anastomose biliodigestiva'], correctIndex: 3 },
  { id: 'ufrj_2024_047', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 35 anos, apresenta hérnia inguinal sintomática. Durante procedimento cirúrgico, identificou-se hérnia inguinal indireta com anel inguinal interno dilatado, além de destruição da fáscia transversalis do triângulo de Hesselbach. De acordo com a classificação de Nyhus, pode-se afirmar que esta paciente apresenta hérnia tipo:', options: ['III A', 'III B', 'II', 'IV A'], correctIndex: 1 },
  { id: 'ufrj_2024_048', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 45 anos, refere história de dor abdominal em quadrante superior direito associada a pico febril (temperatura axilar = 38ºC). Exame físico: lúcida; orientada; hemodinamicamente estável; ictérica (2+/4+); dor abdominal em hipocôndrio direito, sem sinais de irritação peritoneal. Ultrassonografia (US) do abdome: vesícula biliar com parede de 2mm contendo múltiplos cálculos em seu interior; colédoco medindo 10mm. A principal hipótese diagnóstica e o melhor método diagnóstico a ser solicitado para confirmá- la são:', options: ['colecistite aguda / colangiopancreatografia endoscópica retrógrada', 'colangite / tomografia computadorizada para avaliação de coledocolitíase', 'colangite / ressonância magnética para avaliação de via biliar', 'colecistite aguda / colecistectomia videolaparoscópica'], correctIndex: 2 },
  { id: 'ufrj_2024_049', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que o paciente que possui uma contraindicação absoluta para realização de colecistectomia eletiva, em regime ambulatorial, é:', options: ['homem, 45 anos, com DM mal controlado', 'homem, 55 anos, com angina estável', 'mulher, 22 anos, grávida de 8 semanas', 'mulher, 35 anos, com índice de massa corporal = 61kg/m2'], correctIndex: 3 },
  { id: 'ufrj_2024_050', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 45 anos, com histórico de carcinoma de tireoide tratado previamente com intervenção cirúrgica e radioiodoterapia, apresenta um aumento persistente no nível de tireoglobulina sérica durante o acompanhamento pós- tratamento. Pode-se afirmar que a propedêutica mais apropriada inicialmente para localizar possíveis recorrências ou metástases é:', options: ['ressonância magnética abdominal', 'tomografia computadorizada de tórax', 'cintilografia de corpo inteiro com iodo radioativo (I131)', 'ultrassonografia cervical e biópsia de linfonodo cervical'], correctIndex: 2 },
  { id: 'ufrj_2024_051', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Os endoleaks (vazamentos) pós tratamento endovascular dos aneurismas de aorta são classificados de 1 a 5. Pode-se afirmar que o reparo é sempre indicado nos classificados como:', options: ['2 e 5', '2 e 4', '1 e 3', '4 e 5'], correctIndex: 2 },
  { id: 'ufrj_2024_052', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar, em uma paciente com doença de Crohn, que é uma contraindicação para a estenoplastia:', options: ['uso de inflximabe', 'múltiplas estenoses em um segmento curto', '5 estenoses < de 2cm, distantes entre si no íleo', 'necessidade de ressecção em outro segmento no cólon ou íleo'], correctIndex: 1 },
  { id: 'ufrj_2024_053', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Estima-se a baricidade de uma solução de anestésico local dividindo-se a sua densidade pela densidade do líquido cefalorraquidiano (LCR) à 370C. Pode-se afirmar, sobre a baricidade dos anestésicos locais, utilizados na raquianestesia, que:', options: ['soluções de anestésicos locais preparadas em água possuem gravidade especifica ligeiramente menor que o LCR e tendem a subir contra a gravidade', 'soluções hiperbáricas são menos densas que o LCR e tendem a seguir a gravidade após a injeção', 'soluções isobáricas são tão densas quanto o LCR e tendem a seguir a gravidade após a injeção', 'a baricidade das soluções de anestésicos locais não é um fator determinante importante para o nível e duração da raquianestesia'], correctIndex: 0 },
  { id: 'ufrj_2024_054', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar, em relação à queimadura de segundo grau superficial, que:', options: ['não formam bolhas', 'são limitadas à derme papilar', 'os folículos pilosos são destruídos', 'apresentam aspecto esbranquiçado'], correctIndex: 1 },
  { id: 'ufrj_2024_055', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar a respeito da anatomia renal que:', options: ['a veia renal esquerda é, via de regra, mais curta do que a veia renal direita', 'os rins estão localizados anteriormente aos músculos psoas maior e quadrado lombar', 'o rim direito, geralmente, se localiza um pouco abaixo do rim esquerdo devido à sua posição sob o fígado', 'os rins são parcialmente envoltos por uma fáscia chamada de fáscia perirrenal (fáscia de Gerota)'], correctIndex: 2 },
  { id: 'ufrj_2024_056', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 45 anos, refere dor em região de fossa ilíaca direita. Após avaliação, teve o diagnóstico de apendicite aguda e foi submetido a apendicectomia videolaparoscópica. Exame histopatológico da peça cirúrgica: adenocarcinoma de apêndice com lesão de 1cm em região média do apêndice. Pode-se afirmar que a melhor conduta terapêutica a seguir é:', options: ['observação e novos exames de imagem em 6 meses', 'colectomia direita com linfadenectomia', 'observação sem necessidade de acompanhamento com exame de imagem', 'ileotiflectomia'], correctIndex: 1 },
  { id: 'ufrj_2024_057', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 49 anos, recém diagnosticada com carcinoma de células renais, desenvolve quadro de aumento de fosfatase alcalina previamente à abordagem cirúrgica. Não há evidência de metástases à distância pelo estadiamento clínico. Pode-se afirmar que a etiologia mais provável da alteração descrita é:', options: ['lise tumoral por alto turnover celular', 'hemólise intravascular por autoimunidade', 'colestase intra-hepática por síndrome paraneoplásica', 'proliferação leucocitária por reação leucemoide'], correctIndex: 2 },
  { id: 'ufrj_2024_058', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se firmar, sobre a confecção de ostomias, que:', options: ['devem ser confecionada entre as fibras musculares do músculo oblíquo externo', 'a colostomia não precisa se projetar mais do que 0,5 a 1,0cm acima do nível da pele', 'a marcação do local de confecção deve ser realizada no pré-operatório com o paciente deitado', 'quando localizadas em regiões de dobras cutâneas facilitam o acoplamento da bolsa coletora'], correctIndex: 1 },
  { id: 'ufrj_2024_059', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'O diagrama esquemático a seguir iden estímulos neurológicos: Pode-se afirmar que a identificação da estrutu como A, B ou C, é:', options: ['X = trato espinotalâmico / local A: sítio de a adrenérgico', 'X = trato retículoespinhal / local B: sítio de ação', 'X = trato espinocerebelar / local C: sítio de a aspartato (NMDA)', 'X = trato corticoespinhal / local C: sítio de ação ntifica a via nociceptiva para transmissão de ura X e o fármaco que atua no local assinalado ação dos agonistas do receptor α2 do sistema o dos opioides ação dos antagonistas do receptor de N-metil-D- o dos anestésicos locais'], correctIndex: 0 },
  { id: 'ufrj_2024_060', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 60 anos, com história de s regurgitação de odor fétido inicia investigação A principal hipótese diagnóstica é:', options: ['acalásia', 'divertículo epifrênico', 'esôfago em quebra-nozes', 'divertículo de Zenker'], correctIndex: 3 },
  { id: 'ufrj_2024_061', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Dentre as opções em contracepção em nosso país se encontram os LARCS (Long-Acting Reversible Contraceptives - métodos de contracepção de longa ação). Pode-se afirmar, a respeito deles, que:', options: ['são métodos com eficácia de uso típico muito próximo ao de uso perfeito', 'o implante de etonogestrel tem duração para até 7 anos de uso', 'a principal ação do implante de etonogestrel é sua ação no muco cervical', 'a composição do DIU de levonorgestrel contém estrógenos e progestágenos'], correctIndex: 0 },
  { id: 'ufrj_2024_062', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'O conhecimento anatômico da pelve é fundamental para o ginecologista. Um dos principais acidentes ósseos é a espinha isquiática, projeção óssea na superfície medial do ísquio, facilmente palpável pela vagina. Pode-se afirmar que a espinha isquiática serve como ponto de: salivação excessiva, disfagia intermitente e o diagnóstica. Esofagograma:', options: ['referência para o hiato genital e o corpo perineal', 'referência para o bloqueio anestésico do nervo ilíaco', 'fixação do ligamento sacroespinhoso', 'fixação da linha pectínea'], correctIndex: 2 },
  { id: 'ufrj_2024_063', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Em pacientes com câncer de colo de útero em idade reprodutiva que desejam ter filhos, a traquelectomia radical é uma opção. Pode-se afirmar que é critério para ser candidata a essa opção terapêutica o estádio clínico:', options: ['IA 1', 'IB 2', 'IIA 1', 'II B'], correctIndex: 0 },
  { id: 'ufrj_2024_064', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 35 anos, sexualmente ativa, contracepção com condom, nuligesta, apresenta queixa de aumento da duração e do fluxo menstrual progressivas há 6 meses. Exame ginecológico: útero em anteroversoflexão (AVF), tamanho normal, móvel, indolor; colo posterior, móvel indolor; anexos impalpáveis. Ecografia transvaginal: imagem uterina corporal, hipoecogênica, de contornos bem definidos, lobulados, medindo 2cm no maior diâmetro desviando o eco endometrial posteriormente. Vídeo- histeroscopia diagnóstica: abaulamento em parede uterina anterior, de aproximadamente 2cm, com componente intracavitário superior a 50%. A principal hipótese diagnóstica é:', options: ['adenomiose difusa', 'leiomioma uterino', 'pólipo endometrial séssil', 'pólipo endometrial fibroso'], correctIndex: 1 },
  { id: 'ufrj_2024_065', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Sobre o ciclo menstrual, é sabido que ele é composto de uma engrenagem fisiológica complexa, que envolve a regulação de hormônios hipotalâmicos, hipofisários e ovarianos. Pode-se afirmar, tendo em vista os conhecimentos sobre a dinâmica do eixo hipotálamo-hipófise- ovário, que o:', options: ['hormônio liberador de gonadotrofinas (GnRH) é liberado de forma contínua pelo hipotálamo, sendo responsável pela liberação de gonadotrofinas hipofisárias', 'hormônio folículo estimulante (FSH) é responsável pelo crescimento folicular que resultará no aumento progressivo da secreção de progesterona na fase folicular do ciclo', 'hormônio luteinizante (LH) tem como finalidade produzir a luteinização das células somáticas foliculares, completar a maturação do óvulo e promover a ovulação', 'aumento dos níveis circulantes de estradiol produzidos pelos folículos ovarianos possui um efeito de estimulação na liberação do hormônio folículo estimulante (FSH) hipofisário'], correctIndex: 2 },
  { id: 'ufrj_2024_066', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 56 anos, sem comorbidades, encontra-se em menopausa há 4 anos. Pode-se afirmar, considerando essas informações e a fisiologia do eixo hipotálamo-hipófise-ovário, que o perfil hormonal mais esperado para ela é hormônio antimülleriano:', options: ['< 0,01ng/mL; inibina B < 10pg/mL; estradiol < 5pg/mL; FSH = 78mUI/mL', '= 1,2ng/mL; inibina B = 110pg/mL; estradiol = 70pg/mL; FSH = 102mUI/mL', '= 0,8ng/mL; inibina B = 100pg/mL; estradiol < 5pg/mL; FSH = 75mUI/mL', '< 0,01ng/mL; inibina B < 10pg/mL; estradiol < 5pg/mL; FSH = 3mUI/mL'], correctIndex: 0 },
  { id: 'ufrj_2024_067', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que um indivíduo com o diagnóstico de pseudo- hermafroditismo masculino por insensibilidade androgênica completa apresenta, respectivamente, os seguintes fenótipo, cariótipo e alteração embriológica:', options: ['feminino; 46XY; regressão dos ductos paramesonéfricos', 'feminino; 46 XX; regressão dos ductos mesonéfricos', 'masculino; 46XX; regressão dos ductos paramesonéfricos', 'masculino; 46XY; regressão dos ductos mesonéfricos'], correctIndex: 0 },
  { id: 'ufrj_2024_068', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que, para a construção do partograma, o registro gráfico deve ser iniciado quando a parturiente estiver na fase ativa do trabalho de parto (duas a três contrações generalizadas em 10 minutos) e dilatação cervical mínima, em centímetros, de:', options: ['4', '2', '3', '5'], correctIndex: 3 },
  { id: 'ufrj_2024_069', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 27 anos, queixa-se de dor abdominal em baixo ventre há 4 dias. Há 2 dias, refere início de febre e leucorreia amarelada. Exame físico: frequência cardíaca (FC) = 96bpm; temperatura axilar = 38,30C; dor à palpação de hipogástrio, sem sinais de descompressão dolorosa. Exame ginecológico: colo com saída de secreção muco purulenta; ao toque, colo doloroso à mobilização; útero em AVF, tamanho normal; regiões anexiais impalpáveis, mas dolorosas. Pode-se afirmar, já que são critérios obrigatórios para seu diagnóstico, que o que levou o ginecologista a pensar no diagnóstico de doença inflamatória pélvica foi a presença de:', options: ['dor à mobilização do colo; leucorreia muco purulenta; febre', 'febre; taquicardia; leucorreia muco purulenta', 'dor à palpação abdominal, à mobilização do colo e à palpação dos anexos', 'leucorreia muco purulenta; dor à palpação abdominal e á palpação dos anexos'], correctIndex: 2 },
  { id: 'ufrj_2024_070', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 36 anos, com história de exposição prévia ao vírus do papiloma humano (HPV), realizou avaliação colpocitológica com evidência de células escamosas atípicas, sem se descartar lesão de alto grau (ASC-H). Foi encaminhada para a avaliação colposcópica que não evidenciou achados anormais, contudo, a zona de transformação não foi visualizada no exame (ZT tipo 3). Pode-se afirmar que o procedimento a ser realizado a seguir, de acordo com as diretrizes brasileiras para o rastreamento do câncer de colo do útero (2ª edição), é:', options: ['conização', 'curetagem de canal cervical', 'repetir citologia em 1 ano', 'indicar estriol vaginal'], correctIndex: 1 },
  { id: 'ufrj_2024_071', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 65 anos, menopausa aos 43 anos, peso = 60kg, altura = 160cm, é tabagista de longa data e ingere 3 drinques/dia. Densitometria óssea: menor T-score no colo do fêmur, medindo -1,6 desvios padrão. O cálculo do índice FRAX revelou risco de fraturas maiores de 4,8% e no quadril 1,8% nos próximos 10 anos. A principal hipótese diagnóstica e as medidas terapêuticas mais adequadas são:', options: ['osteopenia/mudanças de estilo de vida; reposição de vitamina D', 'osteopenia/mudanças de estilo de vida; uso de alendronato ou ibandronato', 'osteoporose/mudanças de estilo de vida; reposição de cálcio e vitamina D', 'osteoporose/mudanças de estilo de vida; uso de raloxifeno ou alendronato'], correctIndex: 0 },
  { id: 'ufrj_2024_072', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 72 anos, queixando-se de “sensação de bola” na vagina há 6 meses. Exame físico: aplicada classificação POP- Q, observa-se parede vaginal anterior com o ponto Ba em +3; na parede vaginal posterior com o ponto Bp em +1; ponto C em -2 e ponto D em -7. Pode-se afirmar que essa paciente apresenta, respectivamente, prolapsos vaginais:', options: ['anterior estágio 3 / posterior estágio 2, além de alongamento hipertrófico do colo', 'anterior estágio 2 / posterior estágio 1, além de prolapso uterino estágio 2', 'anterior estágio 4 / posterior estágio 1, além de alongamento hipertrófico do colo', 'anterior estágio 3 / posterior estágio 1, além de prolapso uterino estágio 3'], correctIndex: 0 },
  { id: 'ufrj_2024_073', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'A endometriose é uma patologia que acomete uma em cada dez mulheres, portanto, é fundamental entender sua fisiopatologia. Pode-se afirmar, sobre as teorias propostas, que:', options: ['a teoria da menstruação retrógrada, descrita por Sampson, não foi bem aceita, pois, a maior parte das mulheres não apresenta refluxo tubário durante o período menstrual', 'dentre os fatores de risco para a ocorrência de endometriose, destacam-se menarca tardia, multiparidade, tempo diminuído de amamentação e história de fluxo menstrual aumentado', 'conforme a teoria da metaplasia celômica, focos de endometriose podem se formar a partir de tecidos normais mediante um processo de transformação metaplásica', 'a teoria das alterações epigenéticas ganhou forças na literatura nos últimos anos pois consegue, isoladamente, explicar todos os tipos de casos descritos até o momento'], correctIndex: 2 },
  { id: 'ufrj_2024_074', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 49 anos, apresenta na mamografia área de microcalcificações pleomórficas medindo cerca de 1,5cm em quadrante superior externo (QSE) de mama direita. Exame físico das mamas sem alterações. Realizada mamotomia da lesão com diagnóstico histopatológico de hiperplasia ductal atípica. Mamografia de controle: microcalcificações residuais no local da biópsia. Pode-se afirmar que a melhor conduta a seguir é realizar uma:', options: ['setorectomia com uso de tamoxifeno por 5 anos', 'quadrantectomia com esvaziamento axilar', 'mastectomia com uso de raloxifeno por 5 anos', 'adenectomia bilateral profilática com biópsia de linfonodo sentinela'], correctIndex: 0 },
  { id: 'ufrj_2024_075', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'A hiperinsulinemia é ocorrência bastante frequente nas pacientes com diagnóstico de síndrome dos ovários policístico (SOP). Pode-se afirmar, tendo em vista a fisiopatogenia da SOP, que a insulina pode interagir para piorar o quadro clínico da síndrome, já que:', options: ['atua de forma sinérgica ao hormônio luteinizante, marcadamente nas células da granulosa', 'em nível hepático, atua reduzindo os níveis de globulina carreadora de hormônios sexuais', 'aumenta a atividade de hormônio folículo estimulante contribuindo para a disfunção folicular', 'aumenta a produção dos androgênios predominantemente em ação direta nas adrenais'], correctIndex: 1 },
  { id: 'ufrj_2024_076', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 29 anos, queixa-se de leucorreia de aspecto esbranquiçado, que surgiu após relação sexual há 5 dias, acrescida a seguir, de discreto prurido vulvar. Exame ginecológico: conteúdo vaginal aumentado, mais espesso e aderido às paredes vaginais; fita de pH vaginal = 3,0; Whiff test negativo; ao toque, colo posterior, móvel, indolor. Pode-se afirmar que, na citologia à fresco, é esperado se observar a presença de:', options: ['cocos e bacilos', 'clue cells', 'protozoários flagelados', 'hifas e esporos'], correctIndex: 3 },
  { id: 'ufrj_2024_077', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que são características de um abortamento incompleto à ultrassonografia:', options: ['qualquer espessura endometrial; tecido heterogêneo que distorce o eco médio endometrial', 'eco endometrial central com espessura entre 8 a 10mm', 'apresentações variadas, incluindo-se hematoma subcoriônico', 'saco gestacional > 20mm e eco embrionário ausente na US transvaginal'], correctIndex: 0 },
  { id: 'ufrj_2024_078', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que, no mecanismo de parto, o desprendimento do polo cefálico fetal se faz por:', options: ['insinuação e sinclitismo', 'flexão e rotação', 'extensão e deflexão', 'restituição e descida'], correctIndex: 2 },
  { id: 'ufrj_2024_079', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'A hiperêmese gravídica pode ser classificada em duas formas clínicas, de acordo com a intensidade. Pode-se afirmar que o quadro clínico mais característico da forma média é êmese por:', options: ['2 a 5 semanas, com perda ponderal moderada entre 6 e 8% do peso pré- gestacional e FC > que 100bpm', '3 a 5 semanas, com perda ponderal moderada de 15% do peso pré-gestacional e FC entre 100-120bpm', '1 a 2 semanas, com perda ponderal leve de 10% do peso pré-gestacional e FC < que 120bpm', '2 a 4 semanas, com perda ponderal discreta de 5% do peso pré-gestacional e FC < que 100bpm'], correctIndex: 3 },
  { id: 'ufrj_2024_080', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que se suspeita de macrossomia fetal quando duas avaliações sucessivas na US do peso estimado do feto ou da circunferência abdominal estão acima do percentil:', options: ['90', '80', '70', '60'], correctIndex: 0 },
  { id: 'ufrj_2024_081', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que representa um critério clínico para o diagnóstico da síndrome antifosfolipídio (SAF) na gestação:', options: ['um ou mais nascimentos prematuros de fetos morfologicamente normais antes de 32 semanas da gestação', 'três ou mais mortes inexplicadas de feto morfologicamente normal, com 10 ou mais semanas de gestação', 'um ou mais episódios clínicos de trombose venosa, arterial ou de pequenos vasos, em qualquer tecido ou órgão', 'uma ou mais perdas fetais consecutivas inexplicadas antes de 8 semanas de gestação, incluídas causas maternas anatômicas ou hormonais'], correctIndex: 2 },
  { id: 'ufrj_2024_082', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Em face dos maiores riscos do parto na apresentação pélvica (AP), uma alternativa é a transformação da AP em apresentação cefálica por meio de manobras externas, o que constitui a versão cefálica externa (VCE). Pode-se afirmar que a condição na qual a VCE deve ser evitada é:', options: ['diabetes melitus', 'primiparidade', 'pré-eclâmpsia', 'oligodramnia'], correctIndex: 3 },
  { id: 'ufrj_2024_083', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que é uma condição que eleva o risco da ruptura uterina durante o trabalho de parto vaginal de mulheres que se submeteram à cesárea, anteriormente:', options: ['idade gestacional > 41 semanas', 'peso fetal > 4.000g', 'amadurecimento do colo com Krause', 'apresentação pélvica'], correctIndex: 0 },
  { id: 'ufrj_2024_084', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que representa um fator de risco para laceração perineal durante o parto:', options: ['peso fetal > 3.800g', 'primeiro período do parto prolongado', 'variedades de posição occipitoposteriores', 'gestante grande multípara'], correctIndex: 2 },
  { id: 'ufrj_2024_085', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'As cardiopatias congênitas acianóticas são as mais frequentes, e, dentre elas, pode-se afirmar estar entre as mais comuns a:', options: ['comunicação interventricular', 'persistência do canal arterial', 'estenose aórtica congênita', 'tetralogia de Fallot'], correctIndex: 0 },
  { id: 'ufrj_2024_086', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que, para o acompanhamento da doença hemolítica perinatal, a avaliação Dopplerfluxométrica da artéria cerebral média pode ser iniciada entre as semanas de gestação:', options: ['22ª e 24ª', '18ª e 20ª', '20ª e 22ª', '16ª e 18ª'], correctIndex: 3 },
  { id: 'ufrj_2024_087', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar sobre o diabetes gestacional que:', options: ['indica-se cesariana quando o feto apresenta peso ˃ 3.500g', 'a dose necessaria de insulina diária reduz com o avançar da IG', 'a medida sequencial da hemoglobina glicada é de pouca utilidade', 'hipoglicemiantes orais são fármacos de escolha no tratamento'], correctIndex: 2 },
  { id: 'ufrj_2024_088', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que, quando há necessidade de suspensão do aleitamento materno já estabelecido, a carbegolina deve ser prescrita:', options: ['dois comprimidos de 0,50 mg, 1 vez/dia durante 2 dias seguidos', 'dois comprimidos de 0,25mg, 2 vezes/dia durante 3 dias seguidos', 'um comprimido de 0,50mg, 1 vez/dia durante 5 dias seguidos', 'um comprimido de 0,25mg, 2 vezes/dia durante 2 dias seguidos'], correctIndex: 3 },
  { id: 'ufrj_2024_089', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'O diagnóstico da obstrução urinária baixa (válvula de uretra posterior) pode ser feito no feto ainda no período gestacional. Há a possibilidade de intervenções cirúrgicas intraútero através de colocação de shunt vesicoamnótico ou de ablação da válvula de uretra posterior for fetoscopia fetal. Pode-se afirmar que o principal objetivo da realização desses procedimentos é:', options: ['restaurar o volume do líquido amniótico para, assim, prevenir a hipoplasia pulmonar', 'desobstruir as vias urinárias com o objetivo principla de preservar a função renal fetal', 'alcançar a diminuição da pressão exercida pela bexiga distendida nos órgãos adjacentes', 'diminuir o volume uterino, e, consequentemente, evitar desconforto materno e parto prematuro'], correctIndex: 0 },
  { id: 'ufrj_2024_090', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Gestante, 25 anos, 21ª semana de gestação gemelar, com esquistossomose hepatoesplênica, é internada em trabalho de parto prematuro. Após episódio de hematêmese, apresenta hipotensão arterial sistêmica e sudorese. Conduta: oxigenioterapia; reposição volêmica e monitorização. Paciente evoluiu com parada cardiorrespiratória em assistolia. Pode-se afirmar que é correto o líder da equipe de reanimação cardiopulmonar (RCP):', options: ['coordenar as compressões cardíacas externa com as ventilação bolsa-válvula- máscara e não solicitar desvio do útero para esquerda (indicado apenas após 25º semana de gestação)', 'solicitar ajuda, um desfibrilador e que a equipe fique “à postos” para realizar uma cesárea perimortem, caso não ocorra retorno da circulação espontânea até o 40 minuto de RCP', 'explicar a necessidade da inclinação da própria paciente com o uso de prancha para garantir o adequado desvio do útero para a esquerda, mesmo que isso afete a qualidade das compressões cardíacas', 'indicar imediata desfibrilação cardíaca, compressões cardíacas externa e, caso não ocorra retorno da circulação espontânea, cesárea perimortem no 50 minuto de RCP'], correctIndex: 1 },
  { id: 'ufrj_2024_091', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Mulher, 35 semanas de gestação, é admitida em período expulsivo. Refere somente 3 consultas pré-natais, mas não sabe informar sobre medicações utilizadas na gestação, assim como doenças associadas. A via de parto é vaginal. Pediatra e obstetra visualizam exposição das alças intestinais do bebê, à direita do cordão umbilical. A principal hipótese diagnóstica e a melhor conduta terapêutica inicial é:', options: ['extrofia de cloaca/atendimento ao recém- nascido na sala de parto e proteção do conteúdo herniado com compressas úmidas', 'onfalocele/atendimento ao recém-nascido na sala de parto e proteção do conteúdo herniado com compressas úmidas', 'trauma abdominal pelo parto vaginal/proteção das alças intestinais, redução do conteúdo herniado e rafia da parede abdominal', 'gastrosquise/proteção das alças intestinais expostas com saco plástico estéril, envolvendo a criança dos pés até o tórax'], correctIndex: 3 },
  { id: 'ufrj_2024_092', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menino, 8 anos, no 3º ano do ensino fundamental, é atendido por “dificuldade na escola”. Mãe refere que ele lê e escreve “pior” que os colegas de classe. Relatório escolar: “é necessário a professora repetir a tarefa diversas vezes, já que a criança está sempre dispersa. Além disso, não conclui suas tarefas, perde objetos e é desorganizado. Apresenta períodos de irritabilidade e agressividade quando contrariado, mais agitação psicomotora (não parar quieto e mexe as pernas sem parar)”. A mãe relata que ele se comporta da mesma forma em casa, todavia, ela não via problema nisso, uma vez que ela própria também se descreve como desorganizada. Conta que concluiu o segundo grau, mas, à época, sua professora tinha as mesmas queixas. Seu marido tem curso superior e já trocou de trabalho mais de 5 vezes, pois não consegue seguir as solicitações dos chefes e cumprir prazos. Não sabe informar sobre outros familiares. Exame neurológico: normal, exceto por impersistência motora. A principal hipótese diagnóstica é:', options: ['síndrome de Landau- Kleffner', 'transtorno do espectro autista', 'transtorno do déficit de atenção e hiperatividade', 'síndrome do X-Frágil'], correctIndex: 2 },
  { id: 'ufrj_2024_093', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Em uma criança submetida ao teste do pezinho, encontrou-se hemoglobina S. Com 1 ano de idade, pode-se afirmar que o exame adequado para diagnosticar ou afastar uma hemoglobinopatia é:', options: ['imunofenotipagem para anemia hereditárias', 'eletroforese de proteínas', 'imunoeletroforese', 'eletroforese de hemoglobinas'], correctIndex: 3 },
  { id: 'ufrj_2024_094', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menino, 12 anos, com dieta de exclusão de leite e derivados devido a alergia à proteína do leite de vaca também tem dificuldade de aceitar vegetais. Pode- se afirmar sobre a suplementação necessária de cálcio para ele que a ingestão adequada, em mg/dia, é de:', options: ['1.300', '700', '500', '250'], correctIndex: 0 },
  { id: 'ufrj_2024_095', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar, sobre a infecção pelo vírus sincicial respiratório (VSR), que:', options: ['SpO > 95%, história de alimentação ao 2 seio materno exclusivo e nascimento a termo contraindicam internação hospitalar', 'a vacina para VSR está disponível para gestantes e lactentes no Brasil e consiste na principal estratégia de saúde coletiva para a prevenção de surtos da doença', 'o percentual de pacientes que evoluem com gravidade e necessidade de ventilação mecânica é > 15% e justifica internação até completa resolução do quadro de broncoespasmo', 'lactentes que nasceram prematuros ou com cardiopatia grave devem receber terapia profilática com anticorpo monoclonal no primeiro ano de vida para prevenir formas graves da doença'], correctIndex: 3 },
  { id: 'ufrj_2024_096', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Lactente é levada à consulta de puericultura. Não há queixas; aleitamento materno exclusivo. Foi prematura de 36 semanas; peso ao nascimento = 2.880g. Pode-se afirmar que a recomendação da Sociedade Brasileira de Pediatria para a suplementação medicamentosa profilática de ferro elementar, em mg/kg/dia, e o tempo correto para seu início, com dias de vida, são:', options: ['1 / 30', '2 / 30', '1 / 90', '2 / 90'], correctIndex: 1 },
  { id: 'ufrj_2024_097', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menino, 11 anos, é admitido por queixa de cefaleia de forte intensidade de início há 2 meses, em aperto, na região occipital. Há relato que a cefaleia vem aumentando progressivamente de frequência e que não melhora com analgésicos, podendo durar até mais de 6 horas, frequentemente de madrugada. Nega febre associada. No momento, apresenta vômitos e dificuldade de ficar de pé. Exame físico: atáxico e com dismetria; reflexos profundos e força muscular sem anormalidades; paralisia do sexto par craniano, bilateralmente; sem rigidez nuca; sinais de Kernig e Brudzinski negativos. Pode-se afirmar que o principal diagnóstico sindrômico e a mais provável causa da síndrome álgica são:', options: ['infecção meníngea / meningite meningocócica', 'processo expansivo intracraniano / ganglioglioma', 'enxaqueca basilar / inflamatória', 'processo expansivo intracraniano / astrocitoma pilocítico'], correctIndex: 3 },
  { id: 'ufrj_2024_098', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menino, 14 anos, habitualmente, durante os dias da semana, deita-se às 23:30 horas e acorda às 06:00 horas. Nos fins de semana, dorme de 01:00 hora às 13:00 horas. Pode-se afirmar que a melhor recomendação, quanto ao seu tempo de sono é:', options: ['não alterar tempo de sono em nada, pois ele compensa nos finais de semana', 'aumentar tempo de sono para 8-10 horas/noite, igualmente, nos sete dias da semana', 'aumentar tempo de sono para 10-13 horas/noite, igualmente, nos sete dias da semana', 'manter tempo de sono no final de semana igual ao que ele já segue nos 5 dias de semana'], correctIndex: 1 },
  { id: 'ufrj_2024_099', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menina, 4 anos, apresenta quadro de movimentação ocular anormal e “sustos” com 2 meses de evolução. Mãe refere que ela vem apresentando movimentação ocular multidirecional associada a movimentos bruscos de membros superiores e tronco. Ausência de antecedentes patológicos relevantes. Exame físico: regular estado geral; hipocorada (2+/4+); hidratada; anictérica; acianótica; ausculta respiratória normal; FR = 24irpm; ritmo cardíaco regular (RCR) em 2 tempos (2T), sem sopros; FC = 93bpm; PA = 90 x 65mmHg; abdome distendido, indolor, com fígado palpável a 3cm do rebordo costal direito, baço impalpável, presença de massa palpável em flanco esquerdo, endurecida e de limites imprecisos; ataxia cerebelar e movimentos oculares rápidos e irregulares; mioclonia de tronco. Pode-se afirmar que a principal hipótese diagnóstica é:', options: ['feocromocitoma', 'tumor de Wilms', 'adenocarcinoma de adrenal', 'neuroblastoma'], correctIndex: 3 },
  { id: 'ufrj_2024_100', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menina, 15 meses, é encaminhada ao ambulatório de pediatria por atraso do crescimento e desenvolvimento. Não constam informações de pré-natal. As curvas de peso e comprimento encontram- se abaixo do escore-z -2. Há atraso das condutas motoras, pessoais-sociais e de comunicação. Exame físico: fronte olímpica; não segue o estímulo visual por cicatriz em córnea; ausência de reflexo cócleo-palpebral e criança não se vira ao som; fissuras periorais e dentes malformados; tíbia em sabre; alargamento da junção esternoclavicular; artrite indolor de punho e joelhos. A principal hipótese diagnóstica é:', options: ['sífilis congênita', 'raquitismo', 'citomegalovirose congênita', 'escorbuto'], correctIndex: 0 },
  { id: 'ufrj_2024_101', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menino, 4 meses, em aleitamento materno exclusivo, apresenta diarreia há mais de 1 mês e dificuldade em ganhar peso. Exame físico: pequeno abscesso com fistulização na área de aplicação da vacina BCG (bacilo Calmette-Guérin) e adenomegalia em axila direita. Hemograma: anemia hipocrômica e microcítica leve; leucócitos = 6.000/mm3 com 1.300 linfócitos/mm3. A principal hipótese diagnóstica é:', options: ['imunodeficiência combinada grave', 'doença granulomatosa crônica', 'agamaglobulinemia ligada ao X', 'imunodeficiência comum variável'], correctIndex: 0 },
  { id: 'ufrj_2024_102', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Recém-nascido (RN) a termo, com peso ao nascimento de 3.400 gramas, tem alta da maternidade. Pré-natal realizado sem intercorrências. Sem história familiar de doenças. O teste do reflexo vermelho (TRV) foi normal em ambos os olhos. Pode- se afirmar, de acordo com a Sociedade Brasileira de Oftalmologia Pediátrica e a Sociedade Brasileira de Pediatria, que se recomenda a repetição do TRV durante as consultas de puericultura pelo menos:', options: ['1 vez / ano, nos 3 primeiros anos de vida', '1 vez / ano, nos 2 primeiros anos de vida', '2 vezes / ano, nos 2 primeiros anos de vida', '3 vezes / ano, nos 3 primeiros anos de vida'], correctIndex: 3 },
  { id: 'ufrj_2024_103', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menino, 6 anos, com diagnóstico de fibrose cística precoce (triagem neonatal alterada), apresenta tosse produtiva persistente e “sibilância” recorrente há 8 meses. Não há febre. Radiografia do tórax: espessamento peribônquico, principalmente em lobos superiores. Hemogramas repetidos: leucocitose leve e eosinofilia (em torno de 1000-1200/mm3 eosinófilos). TC do tórax recente: bronquiectasias centrais, principalmente à direita. Pode-se afirmar que a complicação que deve ser investigada è:', options: ['síndrome hipereosinofílica', 'aspergilose broncopulmonar alérgica', 'infecção por Burkholderia cepacia', 'bronquiolite obliterante'], correctIndex: 1 },
  { id: 'ufrj_2024_104', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menina, 7 anos, apresenta, há dois dias, febre e diarreia. Há 12 horas, o quadro piorou e surgiram febre alta, dor abdominal e sangue nas fezes, além da diarreia. Pode- se afirmar que, segundo o cartaz atualizado do Ministério da Saúde, sobre manejo do paciente com diarreia, o antibiótico melhor indicado é:', options: ['metronidazol', 'azitromicina', 'amoxicilina', 'ciprofloxacina'], correctIndex: 1 },
  { id: 'ufrj_2024_105', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menina, 5 anos, queixa-se de disúria há 3 dias. Não há febre ou antecedentes patológicos relevantes. Exame físico: bom estado geral; corada; hidratada; FC = 100bpm; frequência respiratória (FR) = 20irpm; PA = 80 x 60mmHg. EAS: presença de nitrito e esterase leucocitária, além de piúria. Pode-se afirmar que o fármaco com melhor relação custo/benefício para o tratamento é:', options: ['oxacilina', 'ceftriaxone', 'claritromicina', 'nitrofurantoína'], correctIndex: 3 },
  { id: 'ufrj_2024_106', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menino, 2 meses, é trazido ao ambulatório por episódios frequentes de regurgitações, choro intenso e ganho ponderal insuficiente. Recentemente, desenvolveu recusa alimentar. Pode-se afirmar, nesse contexto, que a fórmula melhor indicada é:', options: ['extensamente hidrolisada', 'parcialmente hidrolisada', 'de proteína isolada de soja', 'elementar de aminoácidos'], correctIndex: 0 },
  { id: 'ufrj_2024_107', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'No atendimento de puericultura de um lactente com atraso do desenvolvimento, aguardando consulta na rede de saúde para investigação diagnóstica e estimulação, é adequado que o médico da Unidade Básica de Saúde faça as orientações iniciais. Pode- se afirmar que, para estimulação do sentar, o Ministério da Saúde (MS) recomenda que os pais e familiares devem ser orientados a carregar a criança no colo apoiada no:', options: ['antebraço como gangorra com rosto olhando para baixo', 'ombro como conchinha com rosto olhando para trás', 'peito como canguru com rosto olhando para trás', 'braço como cadeirinha com rosto olhando para a frente'], correctIndex: 3 },
  { id: 'ufrj_2024_108', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menino, 5 anos, com diagnóstico de dermatite atópica desde 9 meses, é atendido em consulta de rotina. Mãe refere coriza, prurido e obstrução nasal, mais de 4 vezes por semana, desde os 3 anos. Os sintomas costumam persistir ao longo do dia. Conta, ainda, que ele sempre faz uso de antibiótico para o tratamento de otite. Nega qualquer outra infecção com necessidade outra de antibioticoterapia. Exame físico: bom estado geral; face alongada e palato em ogiva. A conduta inicial mais adequada é prescrever:', options: ['corticoide tópico nasal; anti-histamínico oral nas crises e avaliar existência de hipertrofia de adenoide', 'anti-histamínico oral nas crises e avaliar existência de hipertrofia de adenoide', 'anti-histamínico oral nas crises e dosagem de imunoglobulinas', 'corticoide oral durante um mês; lavagem nasal com soro fisiológico 0,9% e dosagem de imunoglobulinas'], correctIndex: 0 },
  { id: 'ufrj_2024_109', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menina, 1 mês, nascida a termo sem intercorrências, inicia quadro de tosse repetida e persistente com ruído metálico, predominantemente expiratório e episódios de cianose. Mãe não fez pré-natal, mas realizou sorologias para investigação de hepatite B e C, vírus da imunodeficiência humana (HIV) e VDRL (venereal disease research laboratory), com todos os exames negativos no momento do parto. Refere que o quadro de tosse foi precedido por 10 dias de secreção em via respiratória e que possui outra criança, de 5 anos, em casa com sintomas catarrais há 3 semanas. Analise as afirmativas a seguir, considerando-se a principal hipótese diagnóstica: I) Espera-se observar a presença de leucocitose e neutrofilia ao hemograma. II) O início de macrolídeos ou sulfametoxazol-trimetoprim nesta fase dessa doença reduz o contágio, mas não interfere no seu curso. III) O esquema de vacinação pentavalente aos 2, 4 e 6 meses + dois reforços (entre 15- 18 meses e entre 4-6 anos) garante 70% a 90% de eficácia na prevenção desta doença. Pode-se afirmar que está(ão) correta(s) a(s) afirmativa(s):', options: ['I', 'II e III', 'II', 'I e III'], correctIndex: 1 },
  { id: 'ufrj_2024_110', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menina, 3 anos, previamente hígida, está em uso de amoxicilina para tratamento de amigdalite. No oitavo dia de tratamento, apresentou febre, “corpo vermelho e coçando”, dor em ambos os joelhos e punhos. Exame físico: bom estado geral; temperatura axilar = 38,20C; urticárias em tronco, membros e abdome; artralgia em joelhos e punhos. Pode-se afirmar, tendo em vista a principal hipótese diagnóstica, que:', options: ['infusão de imunoglobulina humana é a primeira opção terapêutica', 'as manifestações clínicas são reação ao uso de amoxicilina', 'realização de ECG e ecocardiograma é recomendada', 'é esperado hipocomplementemia, na avaliação laboratorial'], correctIndex: 1 },
  { id: 'ufrj_2024_111', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menino, 10 anos, foi socorrido pelo SAMU e levado ao setor de emergência após queda da laje, altura de aproximadamente 5 metros. Exame físico na admissão: abertura ocular espontânea; choroso; confuso; localiza estímulos dolorosos; pupilas isocóricas e foto reagentes; PA = 110x70mmHg; FC = 90bpm; FR = 25irpm; SpO = 99% em ar ambiente; 2 presença de várias escoriações, dor intensa em perna esquerda com desvio lateral. Realizou exames radiológicos, seguido de internação para correção cirúrgica de fratura em perna. Após 12 horas, apresentou diminuição do nível de consciência, alternando períodos de lucidez e períodos de confusão. Evoluiu rapidamente (poucas horas) para um quadro de: abertura ocular somente aos estímulos dolorosos; emissão de sons incompreensíveis e movimentos de retirada em flexão; anisocoria à direita; PA = 160x100mmHg; FC = 60bpm; FR = 20irpm; SpO = 99% em ar ambiente. A principal 2 hipótese diagnóstica é:', options: ['hematoma subdural', 'encefalopatia hipertensiva', 'hematoma subgaleal', 'coma arreflexo'], correctIndex: 0 },
  { id: 'ufrj_2024_112', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menina, 6 anos, com síndrome do intestino curto, apresentou hiperemia conjuntival e dor ocular. Foi diagnosticado xeroftalmia importante e prescreveu-se colírio lubrificante. Exames laboratoriais: anemia e aumento do volume corpuscular médio (VCM). Pode-se afirmar que provavelmente essa menina possui deficiência das vitaminas:', options: ['B6 e A', 'A e B12', 'C e B12', 'B6 e C'], correctIndex: 1 },
  { id: 'ufrj_2024_113', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que são características do genu varum fisiológico, a idade:', options: ['> 4 anos; não ser progressivo; distancia intermaleolar < 2cm', '> 3 anos; simetria; angulação aguda', '< 1 ano; ser unilateral; inclinação medial da epífise da tíbia proximal', '< 2 anos; simetria; angulo metáfise-diáfise da tíbia proximal < 11 graus'], correctIndex: 3 },
  { id: 'ufrj_2024_114', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menina, 10 anos, apresentou lesão eritemato-descamativa ovalada de 6cm no tórax. Após 2 semanas, apareceram lesões semelhantes e menores, localizadas no tronco. Não houve acometimento palmo- plantar e o quadro teve involução espontânea após 2 meses. Pode-se afirmar que a principal hipótese diagnóstica é:', options: ['liquen plano', 'psoríase', 'pitiríase rósea', 'exantema súbito'], correctIndex: 2 },
  { id: 'ufrj_2024_115', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menino, nascido a termo de parto cesáreo, grande para a idade gestacional, desenvolve nas primeiras horas de vida taquipnéia com retrações e cianose responsiva à suplementação de oxigênio em baixa concentração. Radiografia do tórax: trama vascular pulmonar acentuada; líquido nas cisuras interlobares; hiperaeração. Pode-se afirmar que a principal hipótese diagnóstica é:', options: ['síndrome do desconforto respiratório', 'comunicação interventricular', 'taquipneia transitória do recém-nascido', 'drenagem anômala total de veias pulmonares'], correctIndex: 2 },
  { id: 'ufrj_2024_116', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menina, 60 dias de vida, nascida a termo, apresentou icterícia aos 5 dias de vida, com resolução após 5 dias. Mãe relata que houve retorno da icterícia aos 15 dias de vida, com piora progressiva e percebeu que as fezes estão esbranquiçadas. Exame físico: bom estado geral; eutrófica; ictérica (3+/4+) até zona 3 de Kramer; hepatomegalia, com fígado palpável a 4cm do rebordo costal direito, de consistência endurecida; esplenomegalia, com baço palpável a 2cm do rebordo costal esquerdo. A principal hipótese diagnóstica é:', options: ['hepatite viral aguda', 'atresia de vias biliares', 'colangite esclerosante', 'icterícia fisiológica'], correctIndex: 1 },
  { id: 'ufrj_2024_117', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar, sobre as peculiaridades da fisiologia cardiopulmonar do RN, que:', options: ['enchimento capilar ˃ 2 segundos sugere um desvio sanguíneo dos órgãos centrais à periferia com consequente, hipóxia', 'os pulmões são considerados funcionalmente imaturos e novos bronquíolos terminais e alvéolos continuam a se desenvolver até cerca de 10 anos de idade', 'o pulmão neonatal tem mais pneumócitos tipo II, que produzem surfactante, uma mistura de lipoproteínas de fosfolipídeos, proteínas e gorduras neutras', 'o débito cardíaco é muito dependente da frequência cardíaca, logo, alterações da mesma é um indicador sensível do estado do volume intravascular'], correctIndex: 3 },
  { id: 'ufrj_2024_118', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menino, 7 anos, andou sem apoio com 15 meses, falou as primeiras palavras com 24 meses e sempre se cansava mais rapidamente que os outros colegas nas brincadeiras. Teve dificuldade na alfabetização. Há um ano, está com dificuldade para se levantar do chão e subir escadas. Mãe o leva ao ambulatório por queixa de quedas frequentes, com piora no último ano. Refere que teve um filho que faleceu aos 10 anos por pneumonia, e recorda que o mesmo tinha dificuldades semelhante até chegar a parar de andar com 9 anos. Exame físico: força grau 4/5 nos membros inferiores; reflexos patelares de difícil obtenção; hipertrofia de panturrilhas. Pode-se afirmar que o primeiro exame a ser solicitado para investigar a queixa principal é:', options: ['biópsia muscular', 'eletroneuromiografia', 'creatinafosfoquinase sérica', 'ressonância magnética do encéfalo'], correctIndex: 2 },
  { id: 'ufrj_2024_119', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menino, 2 anos, foi levado ao setor de e há 2 dias. Exame físico: desidratação grave; finos. Foram realizadas inúmeras tentativas de 30 minutos da admissão, evoluiu com perd respiração. Iniciou-se manobras de reanimaç das pás do desfibrilador, observou-se o ritmo Pode-se afirmar que, de acordo com as recom pediatria (PALS), a sequência do atendimento', options: ['acesso venoso profundo com infusão rápida de', 'desfibrilação cardíaca (2J/kg) seguida der verif', 'acesso intraósseo seguido de infusão de adren', 'acesso venoso periférico seguido de bolos de l'], correctIndex: 2 },
  { id: 'ufrj_2024_120', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Menino, 5 meses, é admitido no setor de irritabilidade e baixa ingestão alimentar nas ú inconsolável; afebril; FC = 220bpm, PA = 85x4 palpáveis (periféricos e centrais). ECG a segui O fármaco melhor indicado para o menino, nes', options: ['verapamil', 'procainamida', 'lidocaína', 'adenosina emergência com história de diarreia e vômitos diminuição do nível de consciência e pulsos e acesso venoso periférico sem sucesso. Após da súbita da consciência, sem pulso e sem ção cardiorrespiratória. Com posicionamento cardíaco: mendações do suporte avançado de vida em agora será: e bolos de 20ml/kg de cristaloide ficação do pulso e ritmo cardíaco nalina 0,01mg/kg lidocaína 1mg/kg e terapia intensiva pediátrica com história de últimas 48 horas. Exame físico: irritado; choro 45mmHg; SpO = 97% em ar ambiente; pulsos 2 ir: ste momento é:'], correctIndex: 3 },
  { id: 'ufrj_2024_121', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'O Sistema Único de Saúde (SUS) é uma construção que se processa ao longo da história da Saúde Coletiva no Brasil. Assim, pode-se afirmar que:', options: ['no primeiro Governo de Getúlio Vargas foram assentadas as bases da universalização da saúde no Brasil', 'a Constituição de 1988 teve um forte viés municipalista influenciando o fortalecimento do papel dos municípios na atenção à saúde', 'as leis que institucionalizaram o SUS foram aprovadas no início da década de 2000', 'a V Conferência Nacional de Saúde representou o cume de um movimento social pelo SUS ocorrido na década de 1970'], correctIndex: 1 },
  { id: 'ufrj_2024_122', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar, quanto ao período anterior à 8ª Conferência Nacional de Saúde, que:', options: ['as Caixas de Aposentadoria e Pensão foram criadas com a Constituição Federal de 1945', 'os Institutos de Aposentadoria e Pensões eram financiados, de forma bipartite, pelo governo e pelos trabalhadores.', 'o Instituto Nacional de Previdência Social foi criado durante o regime militar e unificou todos os Institutos de Aposentadoria e Pensões', 'a Lei Elói Chaves foi um marco na construção do SUS, pois estabeleceu o atendimento ao trabalhador rural'], correctIndex: 2 },
  { id: 'ufrj_2024_123', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Analise as afirmativas a seguir com relação ao SUS: I) A ausência de integração e articulação entre os serviços de saúde, com alto grau de fragmentação e desconhecimento das ações oferecidas nos diversos pontos da rede, é um dos fatores que contribui para a baixa qualidade da assistência à saúde. II) Existe um amplo espaço para intervenção dos gestores de saúde nos municípios brasileiros, especialmente em relação às necessidades de atenção básica da população. III) A análise da capacidade instalada em alta complexidade, mostra a presença de salas de unidades intensiva (UTI) na maioria dos municípios brasileiros. Pode-se afirmar que está(ão) correta(s) a(s) afirmativa(s):', options: ['II', 'I e II', 'I', 'II e III'], correctIndex: 1 },
  { id: 'ufrj_2024_124', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que são serviços de ecossistema para as populações humanas, além da provisão:', options: ['regulação; habitat e suporte', 'regulação; suporte e serviços culturais', 'habitat; regulação e serviços culturais', 'suporte; habitat e serviços culturais'], correctIndex: 1 },
  { id: 'ufrj_2024_125', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar, com relação a oferta de serviços de saúde no Brasil, que:', options: ['as maiores disparidades na oferta de serviços ocorrem em relação à infraestrutura física e humana na esfera de atenção básica', 'a capacidade resolutiva do sistema de saúde ocorre de maneira equilibrada e homogênea em todo o território nacional', 'as desigualdades espaciais na oferta de serviços de saúde refletem as disparidades regionais no nível de desenvolvimento social e econômico', 'a maioria dos municípios brasileiros estão aptos a assistir as demandas mais frequentes e comuns da população, que correspondem a cerca de 85% de todas as demandas de saúde'], correctIndex: 2 },
  { id: 'ufrj_2024_126', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar, com relação a concepção de saúde e aos determinantes sociais do processo saúde e doença, que a visão:', options: ['miasmática da doença preconiza o adoecimento como uma disfunção energética interna do organismo', 'miasmática da doença preconiza o adoecimento como a invasão do organismo por uma entidade exterior a ser combatida', 'ontológica da doença preconiza o adoecimento como um desequilíbrio funcional do organismo com o meio que o circunda', 'ontológica da doença preconiza o adoecimento como a invasão do organismo por uma entidade exterior a ser combatida'], correctIndex: 3 },
  { id: 'ufrj_2024_127', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que a confirmação da relação do acidente com o trabalho é feita:', options: ['apenas pelo fiscal da delegacia regional do trabalho', 'exclusivamente pelo médico do trabalho', 'somente pela perícia médica', 'por qualquer profissional de saúde'], correctIndex: 3 },
  { id: 'ufrj_2024_128', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que a perda auditiva induzida pelo ruído apresenta como característica a perda do tipo:', options: ['sensório-neural com comprometimento da orelha interna', 'condutiva com comprometimento da orelha interna', 'sensório-neural com comprometimento da orelha média', 'condutiva com comprometimento da orelha média'], correctIndex: 0 },
  { id: 'ufrj_2024_129', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar, em relação à polineuropatia saturnina nos adultos, que ela é causada pela exposição ao:', options: ['chumbo e acomete tanto as extremidades superiores como inferiores', 'chumbo e acomete com maior frequência as extremidades superiores', 'mercúrio e acomete com maior frequência as extremidades superiores', 'mercúrio e acomete tanto as extremidades superiores como inferiores'], correctIndex: 1 },
  { id: 'ufrj_2024_130', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar, em relação a avaliação e ao planejamento dos cuidados paliativos no fim da vida, que:', options: ['na comunicação de más notícias, durante a consulta médica, o acrônimo P-SPIKES não tem sido mais utilizado, já que foi substituído pela avaliação abrangente dos cuidados paliativos', 'para se conduzir uma avaliação abrangente, deve-se analisar a condição da pessoa, considerando os quatro domínios afetados pela doença (físico, psicológico, social e espiritual)', 'todos os testes invasivos devem ser utilizados nos cuidados de fim de vida, para se avaliar cuidadosamente o estadiamento da doença, com o objetivo de ofertar um prognóstico seguro à família', 'a fim de se conduzir uma avaliação abrangente, deve-se analisar a condição da pessoa, considerando exclusivamente a execução de testes minimamente invasivos e a relação benefício/ônus para o paciente'], correctIndex: 1 },
  { id: 'ufrj_2024_131', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Um estudo de coorte foi conduzido para avaliar a associação entre sedentarismo e desenvolvimento de depressão em adultos. O diagnóstico de depressão foi realizado por meio de um instrumento previamente validado. Sabe-se que este instrumento apresenta sensibilidade de 90% e especificidade de 80%. Os entrevistados e entrevistadores desconheciam a hipótese avaliada. Em função do uso deste instrumento, pode-se afirmar que é passível de ter sido introduzido neste estudo o viés de:', options: ['informação não-diferencial', 'informação diferencial', 'seleção', 'falsa-resposta'], correctIndex: 0 },
  { id: 'ufrj_2024_132', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar, sobre Saúde do Trabalhador, que:', options: ['ocorrência de acidentes e/ou doenças relacionadas ao trabalho, que acometam trabalhadores inseridos tanto no mercado formal como no informal é atribuição exclusiva dos sindicatos dos trabalhadores', 'à equipe de Saúde da Família cabe identificar e registrar a existência de trabalho precoce (crianças e adolescentes ˂ 16 anos, que realizem qualquer tipo de trabalho, com ou sem remuneração, frequentem ou não escolas)', 'realização de orientações trabalhistas e previdenciárias, de acordo com cada caso, é atribuição exclusiva da Assistente Social, membro da equipe multiprofissional na Atenção Primária', 'o trabalho infantil não deve ser considerado como situação de alerta epidemiológico/evento-sentinela, mas, como um agravo a ser, principalmente investigado'], correctIndex: 1 },
  { id: 'ufrj_2024_133', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'As medidas de prevenção de doenças e de agravos relacionados ao trabalho e proteção da saúde do trabalhador devem considerar a hierarquia de controle de riscos, a fim de estruturar as ações de saúde e segurança do trabalhador. Pode-se afirmar que se trata de medida de menor eficiência:', options: ['educação permanente em saúde ao trabalhador', 'reorganização do trabalho', 'adoção de práticas alternativas de trabalho', 'uso de equipamento de proteção individual'], correctIndex: 3 },
  { id: 'ufrj_2024_134', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar, a respeito de Educação em Saúde na Atenção Primária, que:', options: ['práticas educativas somente podem ser realizadas por especialistas em Medicina Família e Comunidade, por serem profissionais expertos em Atenção Primária, aptos, portanto, a elaborarem e conduzirem processos de educação permanente', 'contribui para a afirmação do SUS como uma política pública que tem proporcionado maior inclusão social, não somente por promover a apropriação do significado de saúde enquanto direito por parte da população, como também pela promoção da cidadania e da participação social', 'não tem como objetivo precípuo contribuir para o controle social, embora se almeje estimular a autonomia dos usuários, a partir, principalmente, de práticas educativas exclusivamente ensinadas por médicos de Família e Comunidade', 'práticas educativas tradicionais não podem ser transformadas em práticas pedagógicas que mobilizam a defesa do SUS na Atenção Primária, porque esta é uma prerrogativa exclusiva das categorias sindicais, responsáveis por movimentos sociais que lutam em prol de dignidade'], correctIndex: 1 },
  { id: 'ufrj_2024_135', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar, em relação a triagem e prevenção de doenças, que:', options: ['intervenções preventivas incluem aconselhamento sobre comportamentos vulneráveis, vacinas, medicamentos e, em alguns cenários incomuns, procedimentos cirúrgicos', 'geralmente, a triagem é menos eficaz quando aplicada a distúrbios relativamente comuns, uma vez que estes distúrbios carregam uma grande carga de doenças', 'independentemente do desenho do estudo para avaliar a eficácia da triagem, é fundamental que a duração da sobrevida da doença seja o desfecho primário e não a incidência ou mortalidade da doença', 'na realidade, a ampla maioria da população obtém grande benefício de um teste de triagem, considerando-se, sobretudo, o aumento na expectativa de vida'], correctIndex: 0 },
  { id: 'ufrj_2024_136', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que o critério da transcendência utilizado na definição da lista de doenças e agravos de notificação compulsória diz respeito à:', options: ['existência de meios efetivos para o controle da doença', 'gravidade; relevância social e impacto econômico da doença', 'capacidade do sistema de detectar todos os casos da doença', 'adaptação à introdução de novas definições de caso da doença'], correctIndex: 1 },
  { id: 'ufrj_2024_137', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Um ensaio clínico randomizado, triplamente encoberto, foi realizado para investigar a efetividade do fármaco X na cura da doença Y em comparação a uma substância placebo, a partir de uma amostra de 1.200 pacientes com diagnóstico confirmado para a doença Y. Ao final do estudo, a estimativa da razão de chances (RC) de cura da doença Y entre o grupo tratado com o fármaco X e o grupo controle foi igual a 2,5, com um intervalo de 95% de confiança entre 1,8 e 3,7. Pode-se afirmar, sobre a interpretação dos resultados, que:', options: ['entre todos os possíveis valores da RC de cura da doença Y, 95% estão incluídos entre 1,8 e 3,7', 'existe uma probabilidade de 95% que o intervalo de 1,8 a 3,7 não contenha a verdadeira RC', 'se repetidas 100 amostras possíveis e construídos os intervalos de confiança para cada uma delas, esperar-se-ia que a verdadeira RC estivesse contida em 95 deles', 'a probabilidade de aceitar corretamente a hipótese alternativa indicativa da efetividade do fármaco X na cura da doença Y é de, ao menos, 95%'], correctIndex: 2 },
  { id: 'ufrj_2024_138', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pesquisadores realizaram um estudo seccional para investigar os fatores associados à prevalência de excesso de peso na adolescência, a partir de uma amostra aleatória de adolescentes entre 11 e 19 anos. A idade média dos adolescentes selecionados para compor a população de estudo foi de 15 anos, com desvio padrão de 1,5 anos. Observou-se um padrão simétrico de dispersão das idades observadas em torno da idade média, típico de uma distribuição normal ou gaussiana. Pode-se afirmar, a respeito da distribuição da idade na amostra selecionada, que:', options: ['5% das idades observadas são maiores que 18,0 anos', 'a idade mediana é maior que a idade modal e menor que idade média', '95% da idades observadas estão contidas no intervalo entre 13,5 e 16,5 anos', 'a idade mediana e a idade modal são iguais a 15,0 anos'], correctIndex: 3 },
  { id: 'ufrj_2024_139', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Homem, 56 anos, com DM e HAS, possui, há 8 anos, diagnóstico de cirrose hepática pelo vírus da hepatite C (contraído há 10 anos). Há 5 anos, evoluiu com varizes de esofagianas. Recentemente, foi internado com síndrome edemigênica, trombose extensa de veia porta e piora da função renal que melhorou com reposição volêmica. Foi diagnosticado com carcinoma hepatocelular infiltrativo, sem proposta de transplante hepático. Apresentou insuficiência hepática e seguidamente parada cardíaca em assistolia. O óbito foi constatado após 12 dias de internação. Pode-se afirmar, com relação à certificação das causas de morte na declaração médica de óbito, que:', options: ['a hepatite viral C crônica é a causa básica e a cirrose hepática é uma causa contribuinte', 'o carcinoma hepatocelular infiltrativo é a causa básica e a hipertensão arterial sistêmica é uma causa consequencial', 'a hepatite viral C crônica é a causa básica e o carcinoma hepatocelular infiltrativo é uma causa consequencial', 'o carcinoma hepatocelular infiltrativo é a causa básica e a insuficiência hepática é uma causa contribuinte'], correctIndex: 2 },
  { id: 'ufrj_2024_140', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que o registro incorreto de óbitos infantis ocorridos nos minutos imediatos após o parto como natimortos tem como consequência:', options: ['subestimação da razão de mortalidade materna', 'superestimação do coeficiente mortalidade fetal', 'superestimação do coeficiente de mortalidade perinatal', 'subestimação da razão de mortalidade fetal'], correctIndex: 1 },
  { id: 'ufrj_2024_141', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Um ensaio clínico randomizado com 1.500 participantes foi realizado para testar a eficácia de uma nova vacina contra a dengue. Ao final de um ano de seguimento 300 casos novos de dengue foram identificados, dentre eles 56% receberam a nova vacina. Pode-se concluir a respeito da eficácia da nova vacina que:', options: ['as informações disponíveis são insuficientes', 'a vacina é altamente eficaz', 'ela tem uma eficácia intermediária (40% a 60%)', 'a vacina tem baixa eficácia'], correctIndex: 0 },
  { id: 'ufrj_2024_142', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que, no curso da pandemia ao longo de 2020, o progressivo aumento da probabilidade pré-teste de infecção pelo SARS-CoV-2 entre os casos internados com síndrome respiratória aguda grave, aliado à baixa sensibilidade do teste molecular para o diagnóstico de Covid-19, teve como consequência:', options: ['diminuição da razão de verossimilhança para o teste negativo de Covid-19', 'aumento do número de resultados positivos falsos de Covid-19', 'aumento do número de resultados negativos falsos de Covid-19', 'diminuição da razão de verossimilhança para o teste positivo de Covid-19'], correctIndex: 2 },
  { id: 'ufrj_2024_143', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar, de acordo com o Escritório para Avaliação de Tecnologia (Office of Technology Assessment) do Congresso dos Estados Unidos da América, que o conceito de eficiência se refere:', options: ['ao resultado de uma intervenção aplicada sob as condições habituais da prática médica, que incluem as imperfeições de implementação que caracterizam o mundo cotidiano', 'aos efeitos alcançados em relação ao esforço empreendido, em termos de custos, recursos e tempo que foram gastos para alcançá-los, sob condições próximas do ideal ou na prática diária', 'ao resultado de uma intervenção realizada sob condições ideais e bem controladas, como nos centros de excelência', 'aos efeitos alcançados em condições ideais e replicados em condições habituais da prática médica, que incluem as imperfeições de implementação que caracterizam o mundo cotidiano'], correctIndex: 1 },
  { id: 'ufrj_2024_144', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que a magnitude da mortalidade por uma doença em uma determinada população é função da:', options: ['natalidade e da letalidade da doença', 'incidência e da duração média da doença', 'incidência e da letalidade da doença', 'natalidade e da duração média da doença'], correctIndex: 2 },
  { id: 'ufrj_2024_145', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar, sobre o tema saúde sexual e reprodutiva, que:', options: ['a sexualidade é uma dimensão fundamental de todas as etapas da vida de homens e mulheres, presente desde o nascimento até a morte, e abarca aspectos físicos, psicoemocionais e socioculturais', 'os profissionais de saúde, em geral, não possuem dificuldades de abordar os aspectos relacionados à sexualidade ou, mesmo, à saúde sexual de seus pacientes', 'questões psicológicas (como ansiedade, primeiras experiências sexuais tensas, novos parceiros ou dificuldades no relacionamento), não costumam ser a principal causa de ejaculação precoce, já que as causas orgânicas são prevalentes', 'dispareunia (dor genital que ocorre durante a relação sexual), que somente ocorre em mulheres, embora seja mais frequente durante o ato sexual, também pode ocorrer antes ou após o intercurso da relação sexual'], correctIndex: 0 },
  { id: 'ufrj_2024_146', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Um levantamento do Instituto Nacional de Cardiologia (INC) mostra que, entre 2008 e 2022, o número de internações por infarto agudo do miocárdio aumentou no Brasil. Entre os homens, a média mensal passou de 5.282 para 13.645, uma alta de 158%. Entre as mulheres, a média foi de 1.930 para 4.973, um aumento de 157%. O estudo leva em consideração dados do Sistema de Informação sobre Internações Hospitalares do Datasus, do Ministério da Saúde (Agência Brasil,09/07/2023). Analise as afirmativas a seguir sobre o desenho de estudo utilizado na pesquisa descrita anteriormente: I - Neste desenho de estudo é possível associar exposição e doença no nível individual. II - O desenho de estudo aplicado é ideal para gerar hipóteses etiológicas. III - Uma das limitações deste desenho de estudo é a dificuldade de controlar o efeito de potenciais fatores de confundimento. Pode-se afirmar que está(ão) correta(s) a(s) afirmativa(s):', options: ['I', 'II e III', 'II', 'I e II'], correctIndex: 1 },
  { id: 'ufrj_2024_147', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar, com relação aos modelos de causalidade e intervenção sobre os processos de adoecimento, que:', options: ['reforço vacinal constitui basicamente uma ação específica de prevenção secundária', 'no período de pré-patogénese do modelo de história natural surgem sintomas difusos não específicos da doença', 'promoção da saúde se insere no nível de prevenção primária do modelo de história natural da doença', 'estilo de vida é o principal fator de risco considerado no modelo canadense do campo da saúde'], correctIndex: 2 },
  { id: 'ufrj_2024_148', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Novas estimativas da Organização Mundial da Saúde (OMS) mostram que o número total de mortes associadas direta ou indiretamente à pandemia de COVID-19 (descrito como “excesso de mortalidade”) entre 1 de janeiro de 2020 e 31 de dezembro de 2021 foi de aproximadamente 14,9 milhões. “Esses dados preocupantes não apenas apontam para o impacto da pandemia, mas também para a necessidade de todos os países investirem em sistemas de saúde mais resilientes que possam sustentar serviços essenciais de saúde durante crises, incluindo sistemas de informação de saúde mais fortes”, declarou Tedros Adhanom Ghebreyesus, diretor- geral da OMS.“ (OMS, 05/05/2022). Pode-se afirmar que a medida de associação que expressa o excesso de mortalidade devido à pandemia de Covid-19 é denominada:', options: ['razão de riscos', 'risco atribuível', 'razão de taxas', 'razão de chances'], correctIndex: 1 },
  { id: 'ufrj_2024_149', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar que os sistemas de saúde, principalmente baseados no mercado, têm como uma de suas características:', options: ['integralidade', 'igualdade no acesso aos serviços de saúde', 'associação frequente à filantropia para os que não podem pagar', 'serem sistemas de direitos coletivos à saúde'], correctIndex: 2 },
  { id: 'ufrj_2024_150', banca: 'UFRJ', cycle: 'Ciclo Clinico', subject: 'Clinica Medica', text: 'Pode-se afirmar, com relação às ações de vigilância e de promoção da saúde, que:', options: ['nos serviços de saúde, a vigilância sanitária tem como objetivo monitorar a qualidade de tecnologias diagnósticas e terapêuticas utilizadas e todos os processos neles realizados', 'o movimento da promoção da saúde caracteriza-se pela ênfase na organização dos serviços em torno de programas especiais dirigidos ao controle de agravos e riscos específicos, em detrimento dos determinantes gerais sobre a saúde', 'a organização da atenção à saúde baseada no modelo de vigilância da saúde enfatiza o atendimento à demanda espontânea, baseado em procedimentos e serviços especializados', 'entre os objetivos da vigilância epidemiológica da dengue, a detecção oportuna dos casos visando promover tratamento adequado e reduzir a morbidade, a mortalidade e a letalidade é uma medida de prevenção primária'], correctIndex: 0 },
];
